import{_ as a,p as e,q as t,a1 as r}from"./framework-caba6eb2.js";const h={},d=r('<h1 id="关于" tabindex="-1"><a class="header-anchor" href="#关于" aria-hidden="true">#</a> 关于</h1><h3 id="ham安全吗" tabindex="-1"><a class="header-anchor" href="#ham安全吗" aria-hidden="true">#</a> Ham安全吗</h3><p>放心，Ham并不会像某些已经停止服务的小程序一样，将你的学号密码发送到他们的服务器，再进行验证。你的账户信息仅保存在本地，你的手机将直接从学校服务器获取数据，而不会通过第三方转发。</p><p>当然了，Ham有查给分等功能，需要用到后台服务器。但请放心，Ham在传输你的信息时，务必通过你的同意。而且Ham不会直接传输关键信息。你的关键信息（学号等）在进行哈希运算后再传输至服务器，这样我也不知道是谁的成绩。</p><h3 id="为啥暂不开源" tabindex="-1"><a class="header-anchor" href="#为啥暂不开源" aria-hidden="true">#</a> 为啥暂不开源</h3><p>项目里有很多我的账号信息，包括推送服务、苹果的开发者账号等，所以暂时不打算开源。虽然闭源，但它是完全免费的。</p><p>如果你有好的建议，欢迎在gitter一起交流，也欢迎大家在gitter进行技术讨论！</p>',7),i=[d];function n(c,s){return e(),t("div",null,i)}const _=a(h,[["render",n],["__file","index.html.vue"]]);export{_ as default};
